package com.example.sso.controller;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.io.IOException;
import java.net.URI;
import java.net.URISyntaxException;
import java.util.List;

@Controller
public class LogoutController {

    @Value("${sso.logout.default-redirect-url:/login?logout}")
    private String defaultRedirectUrl;

    @Value("${sso.logout.allowed-redirect-domains:}")
    private List<String> allowedRedirectDomains;

    @GetMapping("/logout")
    public void logout(HttpServletRequest request,
                       HttpServletResponse response,
                       @RequestParam(name = "next", required = false) String next) throws IOException {

        // Invalidate the session
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }

        // Clear any authentication cookies if needed
        // SecurityContextHolder.clearContext(); // if using Spring Security

        // Validate and sanitize the redirect URL
        String safeRedirectUrl = validateRedirectUrl(next);

        response.sendRedirect(safeRedirectUrl);
    }

    /**
     * Validates the redirect URL to prevent Open Redirect attacks.
     * Only allows redirects to whitelisted domains or relative paths.
     *
     * SECURITY NOTE: Never redirect to an unvalidated user-supplied URL.
     * An attacker could craft a link like:
     *   /logout?next=https://evil-phishing-site.com/fake-login
     * which would redirect the user to a malicious site after logout,
     * potentially tricking them into entering credentials on a fake login page.
     */
    private String validateRedirectUrl(String redirectUrl) {
        if (redirectUrl == null || redirectUrl.isBlank()) {
            return defaultRedirectUrl;
        }

        // Block any URL containing protocol-relative patterns or dangerous schemes
        String trimmedUrl = redirectUrl.trim();
        if (trimmedUrl.startsWith("//") ||
            trimmedUrl.toLowerCase().startsWith("javascript:") ||
            trimmedUrl.toLowerCase().startsWith("data:") ||
            trimmedUrl.toLowerCase().startsWith("vbscript:") ||
            trimmedUrl.contains("\r") ||
            trimmedUrl.contains("\n") ||
            trimmedUrl.contains("%0d") ||
            trimmedUrl.contains("%0a")) {
            return defaultRedirectUrl;
        }

        // Allow relative URLs (starting with /)
        if (trimmedUrl.startsWith("/") && !trimmedUrl.startsWith("//")) {
            return trimmedUrl;
        }

        // For absolute URLs, validate against the allowed domains whitelist
        try {
            URI uri = new URI(trimmedUrl);
            String host = uri.getHost();
            String scheme = uri.getScheme();

            if (host == null || scheme == null) {
                return defaultRedirectUrl;
            }

            // Only allow http and https schemes
            if (!scheme.equalsIgnoreCase("http") && !scheme.equalsIgnoreCase("https")) {
                return defaultRedirectUrl;
            }

            // Check if the host is in the allowed domains list
            for (String allowedDomain : allowedRedirectDomains) {
                if (allowedDomain != null && !allowedDomain.isBlank()) {
                    String domain = allowedDomain.trim().toLowerCase();
                    String hostLower = host.toLowerCase();
                    if (hostLower.equals(domain) || hostLower.endsWith("." + domain)) {
                        return trimmedUrl;
                    }
                }
            }
        } catch (URISyntaxException e) {
            // Invalid URI, fall through to default
        }

        return defaultRedirectUrl;
    }
}